import{_ as s,c as a,o as i,a4 as t}from"./chunks/framework.nQaBHiNx.js";const E=JSON.parse('{"title":"第三章 不会误解的名字","description":"","frontmatter":{"permalink":"/note/the-art-of-readable-code/03.html"},"headers":[],"relativePath":"computer/book/the-art-of-readable-code/03-第三章 不会误解的名字.md","filePath":"computer/book/the-art-of-readable-code/03-第三章 不会误解的名字.md"}'),e={name:"computer/book/the-art-of-readable-code/03-第三章 不会误解的名字.md"},n=t(`<h1 id="第三章-不会误解的名字" tabindex="-1">第三章 不会误解的名字 <a class="header-anchor" href="#第三章-不会误解的名字" aria-label="Permalink to &quot;第三章 不会误解的名字&quot;">​</a></h1><p>在前一章中，我们将到了如何把信息塞入名字中。本章会关注另一个话题：小心可能会有歧义的名字。</p><div class="tip custom-block"><p class="custom-block-title">关键思想</p><p>要多问自己几遍: “这个名字会被人解读成其他的含义吗？”</p></div><h2 id="推荐使用-min-和-max-来表示包含的极限" tabindex="-1">推荐使用 min 和 max 来表示包含的极限 <a class="header-anchor" href="#推荐使用-min-和-max-来表示包含的极限" aria-label="Permalink to &quot;推荐使用 min 和 max 来表示包含的极限&quot;">​</a></h2><p>假设你的购物车应用程序最多不能超过10件物品：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CART_TOO_BIG_LIMIT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> shopping_cart.num_items() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> CART_TOO_BIG_LIMIT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   Error(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Too Many items in cart.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>这段代码有个经典的“大小差一”缺陷。我们可以把 <code>&gt;=</code> 编程 <code>&gt;</code> 或者通过把 <code>CART_TOO_BIG_LIMIT</code> 变成 11。但问题根源在于 CART_TOO_BIG_LIMIT 是个二义性名字，它的含义到底是“少于”还是“少于且包括”不得而知。</p><p>在这个例子里，名字应当是 <code>MAX_ITEMS_IN_CART</code>。</p><h2 id="推荐使用-first-和-last-来表示包含范围" tabindex="-1">推荐使用 first 和 last 来表示包含范围 <a class="header-anchor" href="#推荐使用-first-和-last-来表示包含范围" aria-label="Permalink to &quot;推荐使用 first 和 last 来表示包含范围&quot;">​</a></h2><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.PrintKeys(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">first</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bart&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">last</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Maggie&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="推荐使用-begin-和-end-来表示包含或排除的范围" tabindex="-1">推荐使用 begin 和 end 来表示包含或排除的范围 <a class="header-anchor" href="#推荐使用-begin-和-end-来表示包含或排除的范围" aria-label="Permalink to &quot;推荐使用 begin 和 end 来表示包含或排除的范围&quot;">​</a></h2><h2 id="给布尔值命名" tabindex="-1">给布尔值命名 <a class="header-anchor" href="#给布尔值命名" aria-label="Permalink to &quot;给布尔值命名&quot;">​</a></h2><p>当为布尔值变量或者返回布尔值的函数命名时，要确保 true 和 false 的意义很明确。</p><p>通常来讲，加上 is、has、can 或者 should 这样的词，可以把布尔值变得更明确。</p><p>例如，spaceLeft() 函数听上去像是会返回一个数字，如果它的本意是返回一个布尔值，可能 hasSpaaceLeft() 这个名字更好一些。</p><p>最后，最好避免使用反义词名字。</p><p>例如，不要用</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">bool</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> disable_ssl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>而更简单易读的表示方式是：</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">bool</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> use_ssl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h2 id="与使用者的期望相匹配" tabindex="-1">与使用者的期望相匹配 <a class="header-anchor" href="#与使用者的期望相匹配" aria-label="Permalink to &quot;与使用者的期望相匹配&quot;">​</a></h2><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> StatisticsCollector</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">   public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> addSample</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">double</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> x</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) { ... }</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">   public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> double</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> getMean</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(){</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      // Iterate through all samples and return total / num_samples</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>在这个例子中， getMean() 的实现是要遍历所有经过的数据并同时计算其中的值。如果有大量的数据的话，这样的一步可能会有很大的代价！但一个容易轻信的程序员可能会随意地调用 getMean()，还以为这是个没什么代价的调用。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>不会误解的名字是最好的名字——阅读你代码的人应该理解你的本意，并且不会有其他的理解。遗憾的是，很多英语单词在用来编程时是多义性的，例如 filter、length 和 limit。</p><p>在你决定使用一个名字以前，要吹毛求疵一点，来想象一下你的名字会被误解成什么。最好的名字是不会误解的。</p><p>要定义一个值的上限或下限时， max 和 min 时很好的选择。对于包含的范围，first 和 last 时好的选择。对于包含或排除范围，begin 和 end 时最好的选择，因为它们最常用。</p><p>当为布尔值命名时，使用 is 和 has 这样的词来明确表示它是个布尔值，避免使用反义的词例如 dasable_ssl。</p><p>要小心用户对特定词的期望。例如，用户会期望 get() 或者 size() 是轻量的方法。</p>`,29),l=[n];function h(p,k,d,r,o,c){return i(),a("div",null,l)}const u=s(e,[["render",h]]);export{E as __pageData,u as default};
